"use client";

import React, { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { motion, AnimatePresence } from "framer-motion";

interface CycleStatusButtonProps {
statuses: string[];
cycleInterval?: number;
onClick?: () => void;
className?: string;
variant?: "default" | "outline" | "ghost" | "link";
size?: "default" | "sm" | "lg";
}

const CycleStatusButton = ({
statuses,
cycleInterval = 2000,
onClick,
className,
variant = "default",
size = "default",
}: CycleStatusButtonProps) => {
const [currentStatusIndex, setCurrentStatusIndex] = useState(0);

useEffect(() => {
  if (statuses.length <= 1) return;

  const interval = setInterval(() => {
    setCurrentStatusIndex((prev) => (prev + 1) % statuses.length);
  }, cycleInterval);

  return () => clearInterval(interval);
}, [statuses.length, cycleInterval]);

return (
  <motion.div
    layout
    transition={{
      layout: { duration: 0.3 },
    }}
  >
    <Button
      onClick={onClick}
      className={className}
      variant={variant}
      size={size}
    >
      <AnimatePresence mode="wait">
        <motion.span
          key={currentStatusIndex}
          initial={{ opacity: 0, y: 10, filter: "blur(10px)" }}
          animate={{ opacity: 1, y: 0, filter: "blur(0px)" }}
          exit={{ opacity: 0, y: -10, filter: "blur(10px)" }}
          transition={{ duration: 0.3, ease: "easeInOut", delay: 0.1 }}
        >
          {statuses[currentStatusIndex]}
        </motion.span>
      </AnimatePresence>
    </Button>
  </motion.div>
);
};

export default CycleStatusButton;

import * as React from "react"
import { Slot } from "@radix-ui/react-slot"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const buttonVariants = cva(
  "inline-flex items-center justify-center whitespace-nowrap rounded-md text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground hover:bg-primary/90",
        destructive:
          "bg-destructive text-destructive-foreground hover:bg-destructive/90",
        outline:
          "border border-input bg-background hover:bg-accent hover:text-accent-foreground",
        secondary:
          "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        ghost: "hover:bg-accent hover:text-accent-foreground",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default: "h-10 px-4 py-2",
        sm: "h-9 rounded-md px-3",
        lg: "h-11 rounded-md px-8",
        icon: "h-10 w-10",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
)

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, ...props }, ref) => {
    const Comp = asChild ? Slot : "button"
    return (
      <Comp
        className={cn(buttonVariants({ variant, size, className }))}
        ref={ref}
        {...props}
      />
    )
  },
)
Button.displayName = "Button"

export { Button, buttonVariants }
